#include <stdio.h>
#include <stdlib.h>

#define MAX_FILES 100

typedef struct {
    FILE *files[MAX_FILES];
    int count;
} FileHandleManager;

void initManager(FileHandleManager *manager) {
    manager->count = 0;
    for (int i = 0; i < MAX_FILES; i++) {
        manager->files[i] = NULL;
    }
}

int addFileHandle(FileHandleManager *manager, const char *filename, const char *mode) {
    if (manager->count >= MAX_FILES) {
        fprintf(stderr, "Error: Maximum file handles reached.\n");
        return -1;
    }
    FILE *file = fopen(filename, mode);
    if (!file) {
        perror("Error opening file");
        return -1;
    }
    manager->files[manager->count++] = file;
    return 0;
}

int removeFileHandle(FileHandleManager *manager, FILE *file) {
    for (int i = 0; i < manager->count; i++) {
        if (manager->files[i] == file) {
            fclose(manager->files[i]);
            manager->files[i] = manager->files[--manager->count];
            manager->files[manager->count] = NULL;
            return 0;
        }
    }
    fprintf(stderr, "Error: File handle not found.\n");
    return -1;
}

void cleanupManager(FileHandleManager *manager) {
    for (int i = 0; i < manager->count; i++) {
        if (manager->files[i]) {
            fclose(manager->files[i]);
            manager->files[i] = NULL;
        }
    }
    manager->count = 0;
}

int main() {
    FileHandleManager manager;
    initManager(&manager);

    if (addFileHandle(&manager, "example.txt", "r") != 0) {
        fprintf(stderr, "Failed to add file handle.\n");
    }

    cleanupManager(&manager);
    cleanupManager(&manager); // Safe to call multiple times

    return 0;
}